INSERT INTO organization (
  code, name, parent_code, parent_id, org_type, department_type, location, legal_company,
  department_level, cost_center, org_attribute, org_function, effective_start_date, effective_end_date, status
)
SELECT '20000101', '智能制造中心', 'ORG-ROOT', p.id, 'DIVISION', 'BUSINESS_UNIT', 'SUZHOU', 'LE-DEFAULT',
  'L1', 'CC-智能制造', 'PHYSICAL', 'RND', '2020-01-01', NULL, 'ACTIVE'
FROM organization p
WHERE p.code = 'ORG-ROOT' AND p.effective_end_date IS NULL
  AND NOT EXISTS (SELECT 1 FROM organization o WHERE o.code = '20000101' AND o.effective_end_date IS NULL);

